registerModule('Movement Trail', function(g) {
  g._trail = g._trail || {
    points: [],
    maxLength: 48,
    lastX: g.px,
    lastY: g.py
  };

  var trail = g._trail;
  var ctx = g.ctx;
  var dx = g.px - trail.lastX;
  var dy = g.py - trail.lastY;
  var moved = dx * dx + dy * dy > 0.1;

  if (moved) {
    trail.points.push({ x: g.px, y: g.py, age: 0 });
    if (trail.points.length > trail.maxLength) {
      trail.points.shift();
    }
    trail.lastX = g.px;
    trail.lastY = g.py;
  }

  var len = trail.points.length;
  if (len < 2) return;

  for (var i = 1; i < len; i++) {
    var pt = trail.points[i];
    var prev = trail.points[i - 1];
    var t = i / len;
    var alpha = t * t * 0.85;
    var width = t * 3.5;

    // Color shifts from cyan-green to electric blue as trail ages
    var r = Math.round(g.lerp(0, 0, t));
    var gr = Math.round(g.lerp(80, 255, t));
    var b = Math.round(g.lerp(255, 170, t));

    ctx.beginPath();
    ctx.moveTo(prev.x, prev.y);
    ctx.lineTo(pt.x, pt.y);
    ctx.strokeStyle = 'rgba(' + r + ',' + gr + ',' + b + ',' + alpha + ')';
    ctx.lineWidth = width;
    ctx.lineCap = 'round';
    ctx.lineJoin = 'round';
    ctx.stroke();
  }

  // Glow pulse at the tail origin
  if (len > 4) {
    var tail = trail.points[0];
    var pulse = 0.3 + 0.2 * Math.sin(g.tick * 0.18);
    var grad = ctx.createRadialGradient(tail.x, tail.y, 0, tail.x, tail.y, 5);
    grad.addColorStop(0, 'rgba(0,180,255,' + pulse + ')');
    grad.addColorStop(1, 'rgba(0,0,80,0)');
    ctx.beginPath();
    ctx.arc(tail.x, tail.y, 5, 0, Math.PI * 2);
    ctx.fillStyle = grad;
    ctx.fill();
  }
})

