registerModule('Floating Particle Spawner', function(g) {
  g._fps = g._fps || {
    particles: [],
    maxParticles: 120,
    spawnTimer: 0,
    spawnInterval: 8,
    colors: ['#00ffaa','#00ccff','#ff00cc','#ffcc00','#aa00ff','#00ffcc','#ff6600','#66ff00'],
    pulseColors: ['#ffffff','#aaffee','#eeffaa']
  };

  var s = g._fps;
  var ctx = g.ctx;
  var W = g.canvas.width;
  var H = g.canvas.height;

  // Spawn new particles
  s.spawnTimer++;
  if (s.spawnTimer >= s.spawnInterval && s.particles.length < s.maxParticles) {
    s.spawnTimer = 0;

    var edge = Math.floor(g.rand(0, 4));
    var px, py;
    if (edge === 0) { px = g.rand(0, W); py = -8; }
    else if (edge === 1) { px = g.rand(0, W); py = H + 8; }
    else if (edge === 2) { px = -8; py = g.rand(0, H); }
    else { px = W + 8; py = g.rand(0, H); }

    var angle = Math.atan2(H/2 - py, W/2 - px) + g.rand(-0.9, 0.9);
    var speed = g.rand(0.3, 1.4);

    s.particles.push({
      x: px,
      y: py,
      vx: Math.cos(angle) * speed,
      vy: Math.sin(angle) * speed,
      size: g.rand(1.5, 4.5),
      color: s.colors[Math.floor(g.rand(0, s.colors.length))],
      alpha: 0,
      alphaTarget: g.rand(0.5, 1.0),
      life: 0,
      maxLife: g.rand(300, 700),
      wobbleAmp: g.rand(0.0, 0.5),
      wobbleFreq: g.rand(0.02, 0.07),
      wobbleOffset: g.rand(0, Math.PI * 2),
      pulse: Math.random() < 0.18
    });
  }

  // Update and draw particles
  for (var i = s.particles.length - 1; i >= 0; i--) {
    var p = s.particles[i];
    p.life++;

    // Fade in / fade out
    var lifeRatio = p.life / p.maxLife;
    if (lifeRatio < 0.12) {
      p.alpha = g.lerp(p.alpha, p.alphaTarget, 0.08);
    } else if (lifeRatio > 0.75) {
      p.alpha = g.lerp(p.alpha, 0, 0.025);
    }

    // Wobble motion
    var wobble = Math.sin(g.tick * p.wobbleFreq + p.wobbleOffset) * p.wobbleAmp;
    p.x += p.vx + Math.cos(g.tick * p.wobbleFreq + p.wobbleOffset) * p.wobbleAmp * 0.5;
    p.y += p.vy + wobble;

    // Gentle drift toward center over time
    var dx = W/2 - p.x;
    var dy = H/2 - p.y;
    var distC = Math.sqrt(dx*dx + dy*dy);
    if (distC > 60) {
      p.vx += (dx / distC) * 0.004;
      p.vy += (dy / distC) * 0.004;
    }

    // Speed cap
    var spd = Math.sqrt(p.vx*p.vx + p.vy*p.vy);
    if (spd > 1.8) { p.vx = (p.vx/spd)*1.8; p.vy = (p.vy/spd)*1.8; }

    // Absorption check
    var dpx = p.x - g.px;
    var dpy = p.y - g.py;
    var absorb_r = 8 + g.stage * 3;
    if (dpx*dpx + dpy*dpy < absorb_r*absorb_r) {
      // Burst effect
      for (var b = 0; b < 5; b++) {
        var ba = g.rand(0, Math.PI * 2);
        var bs = g.rand(0.8, 2.5);
        g.particles.push({
          x: p.x, y: p.y,
          vx: Math.cos(ba)*bs, vy: Math.sin(ba)*bs,
          life: 0, maxLife: g.rand(18, 38),
          color: p.color, size: g.rand(1, 2.5), alpha: 1
        });
      }
      g.score = (g.score || 0) + 1;
      g.absorbed = (g.absorbed || 0) + 1;
      s.particles.splice(i, 1);
      continue;
    }

    // Remove if expired or off screen
    if (p.life >= p.maxLife || p.x < -40 || p.x > W+40 || p.y < -40 || p.y > H+40) {
      s.particles.splice(i, 1);
      continue;
    }

    // Draw glow
    var grd = ctx.createRadialGradient(p.x, p.y, 0, p.x, p.y, p.size * 3.5);
    grd.addColorStop(0, p.color);
    grd.addColorStop(0.4, p.color);
    grd.addColorStop(1, 'rgba(0,0,0,0)');

    ctx.save();
    ctx.globalAlpha = p.alpha * 0.35;
    ctx.beginPath();
    ctx.arc(p.x, p.y, p.size * 3.5, 0, Math.PI * 2);
    ctx.fillStyle = grd;
    ctx.fill();
    ctx.restore();

