registerModule('Absorption Field', function(g) {
  g._field = g._field || {
    active: false,
    radius: 0,
    maxRadius: 180,
    pulsePhase: 0,
    rings: [
      { phase: 0, speed: 0.04 },
      { phase: 2.1, speed: 0.06 },
      { phase: 4.2, speed: 0.03 }
    ],
    absorbed: 0,
    flashTimer: 0
  };

